<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Models\HrPerformanceTemplate;
class CreatePerformanceTemplateAction { public function __construct(private HrAuditService $audit){} public function execute(string $name,array $sections):HrPerformanceTemplate{abort_unless(auth()->user()?->hasHrPermission('hr.performance.manage_templates'),403);abort_if(blank($name)||empty($sections),422);$ids=[];$weight=0;foreach($sections as $section){abort_if(blank($section['title']??null)||empty($section['questions']),422,'Şablon bölümü geçersiz.');foreach($section['questions'] as $q){$id=trim((string)($q['id']??''));$w=(float)($q['weight']??0);abort_if($id===''||in_array($id,$ids,true)||blank($q['label']??null)||$w<=0,422,'Şablon soruları geçersiz.');$ids[]=$id;$weight+=$w;}}abort_if(abs($weight-100)>0.01,422,'Soru ağırlıkları toplamı 100 olmalıdır.');$tenant=app(TenantContext::class)->getId();$version=(int)HrPerformanceTemplate::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('name',trim($name))->max('version')+1;$template=HrPerformanceTemplate::create(['legal_entity_id'=>$tenant,'name'=>trim($name),'version'=>$version,'sections'=>$sections,'is_active'=>true,'created_by'=>auth()->id()]);$this->audit->log('performance_template_created',$template,null,['version'=>$version]);return $template;} }
